import re

with open('main.tex') as f:
    content = f.read()

text = re.sub(r'\$.*?\$', '', content)
text = re.sub(r'\\[a-zA-Z]+(\[.*?\])?\{.*?\}', '', text)
text = re.sub(r'\\[a-zA-Z]+', '', text)
text = re.sub(r'\{|\}', '', text)
text = re.sub(r'\\cite\{[^}]*\}', '', text)
text = re.sub(r'\\ref\{[^}]*\}', '', text)
text = re.sub(r'\\label\{[^}]*\}', '', text)
text = re.sub(r'\\lq|\\rq', '', text)

words = re.findall(r'[A-Za-z][a-z]+', text)

