potential = []
for w in sorted(set(words)):
    wl = w.lower()
    if len(wl) <= 2:
        continue
    if wl in common:
        continue
    potential.append(w)

for w in potential:
    print(w)

print(f'\n--- {len(potential)} potential issues ---')
